import { moduleMetadata } from '@storybook/angular';
import { PfCardComponent, PfCardHeaderComponent, PfCardBodyComponent, PfCardFooterComponent, } from './card.component';
import { PfButtonComponent } from '../button/button.component';
const meta = {
    title: 'Composants/Card',
    component: PfCardComponent,
    tags: ['autodocs'],
    parameters: {
        docs: {
            description: {
                component: "Conteneur d'aperçu structuré (header, body, footer). 3 variantes : default, elevated, flat. [→ Description complète & bonnes pratiques](?path=/docs/documentation-générale-composants-card--docs)",
            },
        },
    },
    decorators: [
        moduleMetadata({
            imports: [
                PfCardComponent,
                PfCardHeaderComponent,
                PfCardBodyComponent,
                PfCardFooterComponent,
                PfButtonComponent,
            ],
        }),
        (storyFn) => {
            const story = storyFn();
            return { ...story, template: `<div style="width: 420px;">${story.template}</div>` };
        },
    ],
    argTypes: {
        variant: { control: 'inline-radio', options: ['default', 'elevated', 'flat'] },
    },
    args: { variant: 'default' },
    render: (args) => ({
        props: args,
        template: `
      <pf-card [variant]="variant">
        <pf-card-header title="Titre de la card" subtitle="Un sous-titre descriptif"></pf-card-header>
        <pf-card-body>
          <p style="margin: 0">
            Contenu principal de la carte. Les régions sont des sous-composants
            <code>pf-card-header</code>, <code>pf-card-body</code>, <code>pf-card-footer</code>.
          </p>
        </pf-card-body>
        <pf-card-footer>
          <pf-button variant="secondary" size="sm">Annuler</pf-button>
          <pf-button size="sm">Valider</pf-button>
        </pf-card-footer>
      </pf-card>
    `,
    }),
};
export default meta;
export const Default = {};
export const Elevated = { args: { variant: 'elevated' } };
export const Flat = { args: { variant: 'flat' } };
export const BodyOnly = {
    render: () => ({
        template: `
      <pf-card>
        <pf-card-body>Une carte minimale sans header ni footer.</pf-card-body>
      </pf-card>
    `,
    }),
};
